// n8n Code node — manual memory using Workflow Static Data
// Use this when the Memory Manager node is not available.

const sessionId = $json.session_id;           // e.g. "user-42"
const userMessage = $json.message;

// Retrieve stored history (persists across executions)
const history = $getWorkflowStaticData("global")[sessionId] || [];

// Build messages array for the OpenAI node
const messages = [
  { role: "system", content: "You are a helpful assistant." },
  ...history,
  { role: "user", content: userMessage },
];

// Pass to next node (OpenAI Chat Model)
return [{ json: { messages, session_id: sessionId } }];

// n8n Code node — store assistant reply in Static Data
// Place this AFTER the OpenAI node that returns the reply.

const sessionId   = $json.session_id;
const userMessage = $json.original_user_message;
const reply       = $json.message.content;

const store   = $getWorkflowStaticData("global");
const history = store[sessionId] || [];

history.push({ role: "user",      content: userMessage });
history.push({ role: "assistant", content: reply       });

// Keep only the last 20 turns to avoid context overflow
store[sessionId] = history.slice(-20);
$setWorkflowStaticData("global", store);

return [{ json: { reply } }];

# Calling a Dify Workflow from n8n (integration pattern)
# Use case: n8n handles triggers (Slack, email, calendar) and routes to
# a Dify workflow for the LLM-heavy processing steps.

# In n8n — HTTP Request node:
{
  "method": "POST",
  "url": "http://your-dify-host/v1/workflows/run",
  "headers": {
    "Authorization": "Bearer app-xxxxxxxxxxxx",
    "Content-Type": "application/json"
  },
  "body": {
    "inputs": {
      "customer_email": "={{ $json.email }}",
      "ticket_text":    "={{ $json.body }}"
    },
    "response_mode": "blocking",
    "user":           "n8n-bot"
  }
}

# The Dify workflow handles: classify intent → generate reply → format output
# n8n then routes the Dify output to Zendesk, Slack, or email as needed.
# This separates infrastructure concerns (n8n) from LLM logic (Dify).
